# Setup logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s',
    handlers=[
        logging.FileHandler('installation.log'),
        logging.StreamHandler()
    ]
)
logger = logging.getLogger(__name__)

class AlphaOmegaInstaller:
    """
    Comprehensive installer for Alpha Omega system
    """
    
    def __init__(self):
        self.python_version = sys.version_info
        self.system = platform.system()
        self.architecture = platform.architecture()[0]
        self.is_admin = self._check_admin_rights()
        
        # Installation paths
        self.base_path = Path.cwd()
        self.models_path = self.base_path / "models"
        self.data_path = self.base_path / "data"
        self.logs_path = self.base_path / "logs"
        self.sounds_path = self.base_path / "sounds"
        self.temp_path = self.base_path / "temp"
        
        # Configuration
        self.config_file = self.base_path / "config.yaml"
        self.venv_path = self.base_path / "venv"
        
        logger.info(f"Alpha Omega Installer initialized")
        logger.info(f"Python: {self.python_version.major}.{self.python_version.minor}.{self.python_version.micro}")
        logger.info(f"System: {self.system} {self.architecture}")
        logger.info(f"Admin rights: {self.is_admin}")
    
    def install_python_dependencies(self) -> bool:
        """Install Python dependencies"""
        logger.info("Installing Python dependencies...")
        
        # Core dependencies
        core_deps = [
            "numpy>=1.21.0",
            "opencv-python>=4.5.0",
            "pyautogui>=0.9.54",
            "pyperclip>=1.8.2",
            "keyboard>=0.13.5",
            "mouse>=0.7.1",
            "psutil>=5.8.0",
            "pyyaml>=6.0",
            "requests>=2.28.0",
            "pillow>=9.0.0",
            "screeninfo>=0.8.0"
        ]
        
        # Voice and audio dependencies
        voice_deps = [
            "pyaudio>=0.2.11",
            "pyttsx3>=2.90",
            "whisper-openai>=20230314",
            "simpleaudio>=1.0.4",
            "pycaw>=20230407"
        ]
        
        # AI and ML dependencies
        ai_deps = [
            "torch>=1.12.0",
            "transformers>=4.20.0",
            "llama-cpp-python>=0.2.0",
            "chromadb>=0.4.0",
            "scikit-learn>=1.1.0"
        ]
        
        # Windows-specific dependencies
        windows_deps = [
            "pywin32>=304",
            "wmi>=1.5.1"
        ]
        
        # Web and automation dependencies
        web_deps = [
            "selenium>=4.0.0",
            "beautifulsoup4>=4.11.0",
            "flask>=2.2.0",
            "flask-socketio>=5.3.0"
        ]
        
        # Development and testing dependencies
        dev_deps = [
            "pytest>=7.0.0",
            "black>=22.0.0",
            "flake8>=5.0.0"
        ]
        
        # Combine all dependencies
        all_deps = core_deps + voice_deps + ai_deps + web_deps + dev_deps
        
        if self.system == "Windows":
            all_deps += windows_deps
        
        # Install dependencies
        success = True
        failed_deps = []
        
        for dep in all_deps:
            try:
                logger.info(f"Installing {dep}...")
                subprocess.check_call([
                    sys.executable, "-m", "pip", "install", dep,
                    "--no-warn-script-location"
                ], stdout=subprocess.DEVNULL, stderr=subprocess.PIPE)
                logger.info(f"✅ {dep} installed successfully")
                
            except subprocess.CalledProcessError as e:
                logger.warning(f"⚠️  Failed to install {dep}: {e}")
                failed_deps.append(dep)
                success = False
            except Exception as e:
                logger.error(f"❌ Error installing {dep}: {e}")
                failed_deps.append(dep)
                success = False
        
        if failed_deps:
            logger.warning(f"Some dependencies failed to install: {failed_deps}")
            logger.info("System will still work with reduced functionality")
        
        logger.info("Python dependencies installation completed")
        return success
    
